#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
int n,m;
double a[N],s[4*N],q[4*N],t[4*N];

int ls(int x){return (x<<1);}
int rs(int x){return (x<<1|1);}

void push_up(int x){
    s[x]=s[ls(x)]+s[rs(x)];
    q[x]=q[ls(x)]+q[rs(x)];
    return;
}
void build(int x,int l,int r){
    if(l==r){
        s[x]=a[l];
        q[x]=a[l]*a[l];
        return;
    }
    int mid=(l+r)>>1;
    build(ls(x),l,mid);
    build(rs(x),mid+1,r);
    push_up(x);return;
}
void add(int x,int l,int r,double k){
    q[x]+=2*k*s[x]+(r-l+1)*k*k;
    s[x]+=(r-l+1)*k;
    t[x]+=k;return;
}
void push_down(int x,int l,int r){
    if(!t[x])return;
    int mid=(l+r)>>1;
    add(ls(x),l,mid,t[x]);
    add(rs(x),mid+1,r,t[x]);
    t[x]=0;return;
}
void change(int x,int l,int r,int L,int R,double k){
    if(R<l||r<L)return;
    if(L<=l&&r<=R){add(x,l,r,k);return;}
    push_down(x,l,r);
    int mid=(l+r)>>1;
    change(ls(x),l,mid,L,R,k);
    change(rs(x),mid+1,r,L,R,k);
    push_up(x);return;
}
double asksum(int x,int l,int r,int L,int R){
    if(R<l||r<L)return 0;
    if(L<=l&&r<=R)return s[x];
    push_down(x,l,r);
    int mid=(l+r)>>1;
    return asksum(ls(x),l,mid,L,R)+asksum(rs(x),mid+1,r,L,R);
}
double asksqa(int x,int l,int r,int L,int R){
    if(R<l||r<L)return 0;
    if(L<=l&&r<=R)return q[x];
    push_down(x,l,r);
    int mid=(l+r)>>1;
    return asksqa(ls(x),l,mid,L,R)+asksqa(rs(x),mid+1,r,L,R);
}

int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)cin>>a[i];
    build(1,1,n);
    while(m--){
        int opt;cin>>opt;
        if(opt==1){
            int x,y;cin>>x>>y;
            double k;cin>>k;
            change(1,1,n,x,y,k);
        }
        else if(opt==2){
            int x,y;cin>>x>>y;
            double p=asksum(1,1,n,x,y);
            double ans=p/(y-x+1);
            printf("%.4lf\n",ans);
        }
        else{
            int x,y;cin>>x>>y;
            double p=asksum(1,1,n,x,y);
            double f=asksqa(1,1,n,x,y);
            double h=p/(y-x+1);
            double ans=f/(y-x+1)-2*p*h/(y-x+1)+h*h;
            printf("%.4lf\n",ans);
        }
    }
    return 0;
}
